<?php require_once __DIR__ . '/../includes/config.php'; $message=''; $ok=false; if(isset($_POST['install'])){ $conn=@mysqli_connect('localhost','root',''); if(!$conn){ $message='Could not connect to MySQL. Start MySQL in XAMPP first.'; } else { $sql=file_get_contents(__DIR__.'/../database/database.sql'); if(mysqli_multi_query($conn,$sql)){ do{ if($result=mysqli_store_result($conn)){ mysqli_free_result($result); } }while(mysqli_more_results($conn)&&mysqli_next_result($conn)); $ok=true; $message='Installation complete. Database and sample accounts created.'; } else { $message='SQL error: '.mysqli_error($conn); } } } ?>
